import './ToolbarItem.scss';

import { Icon } from ':components/Icon';
import { Menu, MenuItem } from ':components/Menu';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import React, { useRef } from 'react';

import type { ToolbarItemProps } from './ToolbarItem.types';

export const ToolbarItem: React.FC<ToolbarItemProps> = ({
	label,
	icon,
	selected,
	disabled,
	onClick,
	size = 'medium',
	menu,
}) => {
	const itemRef = useRef(null);

	return (
		<>
			<div
				ref={itemRef}
				className={classNames(
					'dsb_toolbar__item',
					`dsb_toolbar__item-${size}`,
					disabled && 'dsb_toolbar__item-disabled',
					selected && 'dsb_toolbar__item-selected',
				)}
				onClick={onClick}
			>
				{icon && <Icon color={icon.color} size={size} iconName={icon.iconName} />}
				<Typography variant={'body3'}>{label}</Typography>
			</div>
			{menu && (
				<Menu onOutsideClick={menu.onOutsideClick} isOpen={menu.isOpen} parent={itemRef}>
					{menu.items.map((item, index) => (
						<MenuItem
							iconName={item?.iconName}
							subtitle={item?.subtitle}
							disabled={item.disabled}
							onClick={item.onClick}
							key={index}
							title={item?.title}
						/>
					))}
				</Menu>
			)}
		</>
	);
};
